def predict_next_frame(frame, action, xy=None):
    # Create a deep copy of the frame to avoid modifying the original
    next_frame = [row[:] for row in frame]

    if action == "ACTION6":
        x, y = xy
        # Get the current color at the clicked position
        current_color = frame[y][x]

        # Define the color mapping: 9 -> 3
        color_map = {9: 3}

        # Apply the transformation if the current color is in our map
        if current_color in color_map:
            next_frame[y][x] = color_map[current_color]

    return next_frame
